20	// SyntheticQuotaHarness is an in-memory QuotaHarness used by
21	// service-level tests that previously constructed per-harness snapshot
22	// types directly. SupportedLimitIDs and QuotaFreshness are read from
23	// the values supplied at construction time.
24	type SyntheticQuotaHarness struct {
25		name      string
26		limitIDs  []string
27		freshness time.Duration
28	
29		mu         sync.Mutex
30		status     harnesses.QuotaStatus
31		probeCount int
32		probeLatch <-chan struct{}
