69	// SetProbeLatch installs a channel that RefreshQuota's probe blocks on
70	// (after incrementing ProbeCount and before returning). Tests use it
71	// to ensure concurrent RefreshQuota callers collide on the same
72	// single-flight cohort. Pass a closed or nil channel to clear the latch.
73	func (s *SyntheticQuotaHarness) SetProbeLatch(ch <-chan struct{}) {
