103	// QuotaStatus implements harnesses.QuotaHarness.
104	func (s *SyntheticQuotaHarness) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
105		if err := ctx.Err(); err != nil {
106			return harnesses.QuotaStatus{}, err
107		}
108		s.mu.Lock()
109		defer s.mu.Unlock()
110		return s.status, nil
111	}
