288	// Recognized aliases resolve to the first concrete model in the
289	// supplied snapshot's Models slice (falling back to s.snapshot.Models[0]
290	// when the caller passes an empty snapshot).
291	func (s *SyntheticModelDiscoveryHarness) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
292		if _, ok := s.aliasSet[family]; !ok {
293			return "", harnesses.ErrAliasNotResolvable
294		}
295		models := snapshot.Models
296		if len(models) == 0 {
297			models = s.snapshot.Models
298		}
299		if len(models) == 0 {
300			return "", harnesses.ErrAliasNotResolvable
301		}
302		return models[0], nil
303	}
