310	// syntheticExecute emits one success Final event and closes the channel.
311	func syntheticExecute(ctx context.Context) (<-chan harnesses.Event, error) {
312		if err := ctx.Err(); err != nil {
313			return nil, err
314		}
315		data, _ := json.Marshal(harnesses.FinalData{Status: "success", ExitCode: 0})
316		ch := make(chan harnesses.Event, 1)
317		ch <- harnesses.Event{
318			Type:     harnesses.EventTypeFinal,
319			Sequence: 1,
320			Time:     time.Now(),
321			Data:     data,
322		}
323		close(ch)
324		return ch, nil
325	}
