25	type ExecuteDispatchCallbacks struct {
26		RunNative      func(context.Context)
27		RunSubprocess  func(context.Context, harnesses.Harness)
28		RunVirtual     func(context.Context)
29		RunScript      func(context.Context)
30		IsHTTPProvider func(harness string) bool
31		Finalize       func(harnesses.FinalData)
32	}
33	
34	// DispatchExecuteRun selects the concrete runner for an Execute request.
35	func DispatchExecuteRun(ctx context.Context, req ExecuteDispatchRequest, cb ExecuteDispatchCallbacks) {
36		switch req.Decision.Harness {
37		case "fiz", "":
38			if cb.RunNative != nil {
39				cb.RunNative(ctx)
40			}
41		case "claude":
42			runSubprocess(ctx, cb, &claudeharness.Runner{})
43		case "codex":
44			runSubprocess(ctx, cb, &codexharness.Runner{})
45		case "gemini":
46			runSubprocess(ctx, cb, &geminiharness.Runner{})
47		case "opencode":
48			runSubprocess(ctx, cb, &opencodeharness.Runner{})
49		case "pi":
50			runSubprocess(ctx, cb, &piharness.Runner{})
51		case "virtual":
52			if cb.RunVirtual != nil {
53				cb.RunVirtual(ctx)
54			}
55		case "script":
56			if cb.RunScript != nil {
57				cb.RunScript(ctx)
58			}
59		default:
60			if cb.IsHTTPProvider != nil && cb.IsHTTPProvider(req.Decision.Harness) {
61				if cb.RunNative != nil {
62					cb.RunNative(ctx)
63				}
64				return
65			}
66			finalizeDispatch(cb, harnesses.FinalData{
67				Status:     "failed",
68				Error:      fmt.Sprintf("harness %q dispatch not yet wired in service.Execute", req.Decision.Harness),
69				DurationMS: time.Since(req.Started).Milliseconds(),
70				RoutingActual: &harnesses.RoutingActual{
71					Harness:        req.Decision.Harness,
72					Provider:       req.Decision.Provider,
73					ServerInstance: req.Decision.ServerInstance,
74					Model:          req.Decision.Model,
75				},
76			})
77		}
78	}
