package fizeau

import (
	"context"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
)

// refreshScheduler owns the single service-wide async refresh cadence
// across every registered QuotaHarness and AccountHarness. It is the
// replacement for the per-harness Refresh*Async helpers described in
// CONTRACT-004 / plan-2026-05-14-harness-interface-refactor.md Step 4.
//
// One debounced ticker is scheduled per registered QuotaHarness at
// QuotaFreshness()/2 cadence. An independent ticker is scheduled per
// registered AccountHarness only when its AccountFreshness() differs
// from the harness's QuotaFreshness() — when the cadences match, the
// QuotaHarness ticker is sufficient for callers that want to drive
// account refreshes alongside quota.
//
// The scheduler does not enforce single-flight itself. RefreshQuota /
// RefreshAccount are required by CONTRACT-004 to be single-flight per
// harness instance (via the harness's cache lock); the scheduler relies
// on that contract. Cache-freshness deduplication, however, is the
// scheduler's responsibility: it reads QuotaStatus before each refresh
// and skips ticks where CapturedAt is within QuotaFreshness() of now,
// so that RefreshQuota itself can probe unconditionally per
// CONTRACT-004 invariant #4.
//
// Pre-migration (Steps 5–8 of the refactor not yet landed), the
// concrete Runner types do not yet implement QuotaHarness or
// AccountHarness. Type assertions fail and the scheduler registers
// nothing for those harnesses; they continue to use their existing
// Refresh*Async helpers until each harness's e-step deletes them.
type refreshScheduler struct {
	lookup func(name string) harnesses.Harness
	names  []string
	clock  schedulerClock

	// tickNotify, when non-nil, receives the harness name after each
	// tick is fully processed (refresh attempted or skipped). Tests
	// use this to synchronize on tick completion; production leaves
	// it nil.
	tickNotify chan<- string

	mu     sync.Mutex
	ctx    context.Context
	cancel context.CancelFunc
	wg     sync.WaitGroup
}

// schedulerClock is the time abstraction the refresh scheduler uses.
// The production implementation wraps time.Now / time.NewTicker; tests
// inject a controllable fake clock to drive cadence deterministically.
type schedulerClock interface {
	Now() time.Time
	NewTicker(d time.Duration) schedulerTicker
}

// schedulerTicker is a minimal time.Ticker abstraction.
type schedulerTicker interface {
	C() <-chan time.Time
	Stop()
}

// realClock is the wall-clock implementation of schedulerClock.
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }

func (realClock) NewTicker(d time.Duration) schedulerTicker {
	return &realTicker{t: time.NewTicker(d)}
}

type realTicker struct{ t *time.Ticker }

func (r *realTicker) C() <-chan time.Time { return r.t.C }
func (r *realTicker) Stop()               { r.t.Stop() }

// newRefreshScheduler constructs (but does not start) a scheduler over
// the harness names supplied. lookup returns the registered Harness
// instance for each name; a nil result is tolerated and means the name
// is registered but has no live instance, in which case the scheduler
// registers nothing for that name. clock defaults to realClock when
// nil.
func newRefreshScheduler(lookup func(string) harnesses.Harness, names []string, clock schedulerClock) *refreshScheduler {
	if clock == nil {
		clock = realClock{}
	}
	return &refreshScheduler{
		lookup: lookup,
		names:  append([]string(nil), names...),
		clock:  clock,
	}
}

// Start launches the scheduler. For every registered harness, it
// type-asserts to QuotaHarness and AccountHarness independently. For
// each capability the harness satisfies, it:
//
//  1. Reads the current cached status. When the status reports
//     QuotaUnavailable (cache-cold), the scheduler fires one
//     immediate refresh.
//  2. Starts a debounced ticker at Freshness/2 cadence that drives
//     subsequent refreshes.
//
// Start is not safe to call concurrently; concurrent Start panics.
// Call Stop before re-starting.
func (s *refreshScheduler) Start(parent context.Context) {
	s.mu.Lock()
	if s.cancel != nil {
		s.mu.Unlock()
		panic("refreshScheduler: Start called twice without intervening Stop")
	}
	s.ctx, s.cancel = context.WithCancel(parent)
	s.mu.Unlock()

	now := s.clock.Now()
	for _, name := range s.names {
		h := s.lookup(name)
		if h == nil {
			continue
		}
		qh, isQuota := h.(harnesses.QuotaHarness)
		ah, isAccount := h.(harnesses.AccountHarness)

		if isQuota {
			s.startQuotaTicker(name, qh, now)
		}
		if isAccount {
			// Only start a separate account ticker when account
			// freshness differs from quota freshness. When they
			// match, the quota cadence already covers the cache
			// lifetime account refresh would observe; harnesses
			// that want account-aligned refresh can implement it
			// inside RefreshQuota. See CONTRACT-004 / Step 4.
			if !isQuota || ah.AccountFreshness() != qh.QuotaFreshness() {
				s.startAccountTicker(name, ah, now)
			}
		}
	}
}

// Stop cancels the scheduler context and waits for every ticker
// goroutine to exit. Safe to call on a never-started scheduler (no-op).
func (s *refreshScheduler) Stop() {
	s.mu.Lock()
	cancel := s.cancel
	s.cancel = nil
	s.mu.Unlock()
	if cancel == nil {
		return
	}
	cancel()
	s.wg.Wait()
}

// startQuotaTicker fires the cache-cold kickoff (if applicable) and
// launches the per-harness debounced ticker.
func (s *refreshScheduler) startQuotaTicker(name string, qh harnesses.QuotaHarness, now time.Time) {
	interval := qh.QuotaFreshness() / 2
	if interval <= 0 {
		// Misconfigured harness: a non-positive freshness disables
		// scheduling — the scheduler refuses to busy-loop. Surfaced
		// as a CONTRACT-004 violation by the conformance suite.
		return
	}

	// Cache-cold startup kickoff. Per
	// primary-harness-capability-baseline.md and AC #6, the
	// scheduler fires one RefreshQuota immediately when the
	// cached state is QuotaUnavailable.
	if status, err := qh.QuotaStatus(s.ctx, now); err == nil && status.State == harnesses.QuotaUnavailable {
		s.wg.Add(1)
		go func() {
			defer s.wg.Done()
			_, _ = qh.RefreshQuota(s.ctx)
		}()
	}

	ticker := s.clock.NewTicker(interval)
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		defer ticker.Stop()
		for {
			select {
			case <-s.ctx.Done():
				return
			case <-ticker.C():
				s.maybeRefreshQuota(name, qh)
			}
		}
	}()
}

// maybeRefreshQuota implements the per-tick decision. On cache-cold
// (QuotaUnavailable) it always refreshes. Otherwise it skips when
// CapturedAt is within QuotaFreshness() of now (cache-freshness dedup
// is the scheduler's job, not RefreshQuota's). All other tick
// outcomes result in a RefreshQuota call.
func (s *refreshScheduler) maybeRefreshQuota(name string, qh harnesses.QuotaHarness) {
	defer s.notifyTick(name)

	now := s.clock.Now()
	status, err := qh.QuotaStatus(s.ctx, now)
	if err != nil {
		return
	}

	if status.State == harnesses.QuotaUnavailable {
		_, _ = qh.RefreshQuota(s.ctx)
		return
	}

	if !status.CapturedAt.IsZero() && now.Sub(status.CapturedAt) < qh.QuotaFreshness() {
		return
	}

	_, _ = qh.RefreshQuota(s.ctx)
}

// startAccountTicker is the AccountHarness analogue of
// startQuotaTicker. Cache-cold is detected via a zero CapturedAt
// because AccountSnapshot has no explicit "unavailable" state value.
func (s *refreshScheduler) startAccountTicker(name string, ah harnesses.AccountHarness, now time.Time) {
	interval := ah.AccountFreshness() / 2
	if interval <= 0 {
		return
	}

	if snap, err := ah.AccountStatus(s.ctx, now); err == nil && snap.CapturedAt.IsZero() {
		s.wg.Add(1)
		go func() {
			defer s.wg.Done()
			_, _ = ah.RefreshAccount(s.ctx)
		}()
	}

	ticker := s.clock.NewTicker(interval)
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		defer ticker.Stop()
		for {
			select {
			case <-s.ctx.Done():
				return
			case <-ticker.C():
				s.maybeRefreshAccount(name, ah)
			}
		}
	}()
}

// maybeRefreshAccount mirrors maybeRefreshQuota for AccountHarness.
func (s *refreshScheduler) maybeRefreshAccount(name string, ah harnesses.AccountHarness) {
	defer s.notifyTick(name)

	now := s.clock.Now()
	snap, err := ah.AccountStatus(s.ctx, now)
	if err != nil {
		return
	}

	if snap.CapturedAt.IsZero() {
		_, _ = ah.RefreshAccount(s.ctx)
		return
	}

	if now.Sub(snap.CapturedAt) < ah.AccountFreshness() {
		return
	}

	_, _ = ah.RefreshAccount(s.ctx)
}

// notifyTick fans out a tick-processed notification when tickNotify is
// set. Never blocks the scheduler goroutine on the receiver.
func (s *refreshScheduler) notifyTick(name string) {
	if s.tickNotify == nil {
		return
	}
	select {
	case s.tickNotify <- name:
	case <-s.ctx.Done():
	}
}

package fizeau

import (
	"context"
	"sync"
	"testing"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/harnesstest"
)

// fakeClock is a controllable clock for refreshScheduler tests. Time
// only advances when the test calls Advance; tickers fire synchronously
// from the caller's goroutine when their next-fire instant is reached.
type fakeClock struct {
	mu      sync.Mutex
	now     time.Time
	tickers []*fakeTicker
}

func newFakeClock(start time.Time) *fakeClock {
	return &fakeClock{now: start}
}

func (c *fakeClock) Now() time.Time {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.now
}

func (c *fakeClock) NewTicker(d time.Duration) schedulerTicker {
	c.mu.Lock()
	defer c.mu.Unlock()
	t := &fakeTicker{
		c:        make(chan time.Time, 1),
		interval: d,
		next:     c.now.Add(d),
	}
	c.tickers = append(c.tickers, t)
	return t
}

// Advance moves the fake clock forward by d and fires every ticker
// whose next-fire instant is at or before the new now. Each ticker
// fires at most once per Advance — chained ticks within a single
// Advance window are coalesced (matching time.Ticker's drop-on-full
// behavior).
func (c *fakeClock) Advance(d time.Duration) {
	c.mu.Lock()
	c.now = c.now.Add(d)
	target := c.now
	tickers := append([]*fakeTicker(nil), c.tickers...)
	c.mu.Unlock()
	for _, t := range tickers {
		t.fireUpTo(target)
	}
}

type fakeTicker struct {
	c        chan time.Time
	interval time.Duration

	mu      sync.Mutex
	next    time.Time
	stopped bool
}

func (t *fakeTicker) C() <-chan time.Time { return t.c }

func (t *fakeTicker) Stop() {
	t.mu.Lock()
	defer t.mu.Unlock()
	t.stopped = true
}

func (t *fakeTicker) fireUpTo(now time.Time) {
	t.mu.Lock()
	defer t.mu.Unlock()
	if t.stopped {
		return
	}
	for !now.Before(t.next) {
		select {
		case t.c <- t.next:
		default:
		}
		t.next = t.next.Add(t.interval)
	}
}

// waitForTick waits for the scheduler to publish a tick-completed
// notification for any harness, or fails the test on timeout.
func waitForTick(t *testing.T, ch <-chan string, timeout time.Duration) string {
	t.Helper()
	select {
	case name := <-ch:
		return name
	case <-time.After(timeout):
		t.Fatalf("timed out waiting for tick notification after %s", timeout)
		return ""
	}
}

// TestRefreshScheduler_Debounces verifies that the scheduler fires
// RefreshQuota at QuotaFreshness()/2 cadence, and skips ticks when the
// cached CapturedAt is still within QuotaFreshness() of now.
func TestRefreshScheduler_Debounces(t *testing.T) {
	start := time.Date(2026, 5, 14, 12, 0, 0, 0, time.UTC)
	clock := newFakeClock(start)

	freshness := 30 * time.Minute
	// Seed CapturedAt at start time; State=QuotaOK so it isn't
	// treated as cache-cold.
	qh := harnesstest.NewSyntheticQuotaHarness("synth", harnesses.QuotaStatus{
		State:      harnesses.QuotaOK,
		CapturedAt: start,
	}, nil)
	qh.SetQuotaFreshness(freshness)

	notify := make(chan string, 8)
	sched := newRefreshScheduler(func(name string) harnesses.Harness {
		if name == "synth" {
			return qh
		}
		return nil
	}, []string{"synth"}, clock)
	sched.tickNotify = notify

	sched.Start(context.Background())
	t.Cleanup(sched.Stop)

	// Tick 1 at freshness/2 (15m): CapturedAt is 15m old, still
	// within freshness → skip.
	clock.Advance(freshness / 2)
	waitForTick(t, notify, time.Second)
	if got := qh.ProbeCount(); got != 0 {
		t.Fatalf("after first tick: ProbeCount=%d want 0 (still fresh)", got)
	}

	// Tick 2 at freshness (30m total): CapturedAt is 30m old,
	// outside freshness → refresh.
	clock.Advance(freshness / 2)
	waitForTick(t, notify, time.Second)
	if got := qh.ProbeCount(); got != 1 {
		t.Fatalf("after second tick: ProbeCount=%d want 1", got)
	}

	// The refresh stored the same QuotaStatus as before (with the
	// CapturedAt from the original status, which is still `start`).
	// Update synthetic status to reflect "just refreshed" so the
	// next tick is correctly classified as still-fresh.
	qh.SetQuotaStatus(harnesses.QuotaStatus{
		State:      harnesses.QuotaOK,
		CapturedAt: clock.Now(),
	})

	// Tick 3 at freshness*1.5 (45m): CapturedAt is 15m old → skip.
	clock.Advance(freshness / 2)
	waitForTick(t, notify, time.Second)
	if got := qh.ProbeCount(); got != 1 {
		t.Fatalf("after third tick: ProbeCount=%d want 1 (still fresh after refresh)", got)
	}
}

// TestRefreshScheduler_StartupKickoff verifies that scheduler
// construction fires a single RefreshQuota for every registered
// QuotaHarness whose cached state is QuotaUnavailable (cache-cold).
func TestRefreshScheduler_StartupKickoff(t *testing.T) {
	start := time.Date(2026, 5, 14, 12, 0, 0, 0, time.UTC)
	clock := newFakeClock(start)

	coldQuota := harnesstest.NewSyntheticQuotaHarness("cold", harnesses.QuotaStatus{
		State: harnesses.QuotaUnavailable,
	}, nil)
	coldQuota.SetQuotaFreshness(30 * time.Minute)

	warmQuota := harnesstest.NewSyntheticQuotaHarness("warm", harnesses.QuotaStatus{
		State:      harnesses.QuotaOK,
		CapturedAt: start,
	}, nil)
	warmQuota.SetQuotaFreshness(30 * time.Minute)

	coldAccount := harnesstest.NewSyntheticAccountHarness("coldacct", harnesses.AccountSnapshot{
		// CapturedAt zero → cache-cold.
	}, 7*24*time.Hour)

	lookup := func(name string) harnesses.Harness {
		switch name {
		case "cold":
			return coldQuota
		case "warm":
			return warmQuota
		case "coldacct":
			return coldAccount
		}
		return nil
	}

	sched := newRefreshScheduler(lookup, []string{"cold", "warm", "coldacct"}, clock)
	sched.Start(context.Background())
	t.Cleanup(sched.Stop)

	// Wait for the startup goroutines to complete by polling.
	deadline := time.Now().Add(time.Second)
	for time.Now().Before(deadline) {
		if coldQuota.ProbeCount() == 1 && coldAccount.ProbeCount() == 1 {
			break
		}
		time.Sleep(2 * time.Millisecond)
	}

	if got := coldQuota.ProbeCount(); got != 1 {
		t.Fatalf("cold QuotaHarness kickoff: ProbeCount=%d want 1", got)
	}
	if got := warmQuota.ProbeCount(); got != 0 {
		t.Fatalf("warm QuotaHarness kickoff: ProbeCount=%d want 0", got)
	}
	if got := coldAccount.ProbeCount(); got != 1 {
		t.Fatalf("cold AccountHarness kickoff: ProbeCount=%d want 1", got)
	}
}

// TestRefreshScheduler_SingleFlight verifies that concurrent
// RefreshQuota callers driven by the scheduler share one underlying
// probe through the harness's cache lock — the scheduler does not
// double-probe under simultaneous tick + external refresh.
func TestRefreshScheduler_SingleFlight(t *testing.T) {
	start := time.Date(2026, 5, 14, 12, 0, 0, 0, time.UTC)
	clock := newFakeClock(start)

	freshness := 30 * time.Minute
	captured := start.Add(-2 * freshness) // stale so the tick refreshes
	qh := harnesstest.NewSyntheticQuotaHarness("synth", harnesses.QuotaStatus{
		State:      harnesses.QuotaOK,
		CapturedAt: captured,
	}, nil)
	qh.SetQuotaFreshness(freshness)

	// Latch: the scheduler's RefreshQuota and an external
	// RefreshQuota must collide in the same single-flight cohort.
	latch := make(chan struct{})
	qh.SetProbeLatch(latch)

	notify := make(chan string, 1)
	sched := newRefreshScheduler(func(name string) harnesses.Harness {
		if name == "synth" {
			return qh
		}
		return nil
	}, []string{"synth"}, clock)
	sched.tickNotify = notify
	sched.Start(context.Background())
	t.Cleanup(sched.Stop)

	// Drive the tick.
	clock.Advance(freshness / 2)

	// External caller races the scheduler. Both should resolve to
	// a single probe.
	externalDone := make(chan struct{})
	go func() {
		_, _ = qh.RefreshQuota(context.Background())
		close(externalDone)
	}()

	// Wait long enough for both callers to enter the probe.
	time.Sleep(20 * time.Millisecond)
	close(latch)

	waitForTick(t, notify, time.Second)
	select {
	case <-externalDone:
	case <-time.After(time.Second):
		t.Fatal("external RefreshQuota did not complete")
	}

	if got := qh.ProbeCount(); got != 1 {
		t.Fatalf("ProbeCount=%d; want exactly one probe under single-flight", got)
	}
}

// TestRefreshScheduler_StopCancelsTickers verifies that Stop cancels
// the scheduler context, all ticker goroutines exit, and no further
// refreshes fire after Stop returns.
func TestRefreshScheduler_StopCancelsTickers(t *testing.T) {
	start := time.Date(2026, 5, 14, 12, 0, 0, 0, time.UTC)
	clock := newFakeClock(start)

	freshness := 30 * time.Minute
	qh := harnesstest.NewSyntheticQuotaHarness("synth", harnesses.QuotaStatus{
		State:      harnesses.QuotaOK,
		CapturedAt: start.Add(-2 * freshness),
	}, nil)
	qh.SetQuotaFreshness(freshness)

	sched := newRefreshScheduler(func(name string) harnesses.Harness {
		if name == "synth" {
			return qh
		}
		return nil
	}, []string{"synth"}, clock)

	sched.Start(context.Background())
	sched.Stop()

	// After Stop returns, the ticker goroutine has exited (wg
	// drained). Subsequent Advance must not race with the goroutine
	// or cause further refreshes.
	before := qh.ProbeCount()
	clock.Advance(freshness * 4)
	// Give any (incorrectly) leaked goroutine time to misbehave.
	time.Sleep(20 * time.Millisecond)
	if got := qh.ProbeCount(); got != before {
		t.Fatalf("post-Stop ProbeCount=%d want %d (no refresh after Stop)", got, before)
	}

	// Stop is idempotent.
	sched.Stop()
}

// TestRefreshScheduler_AccountTickerSkippedWhenSameCadence verifies
// that a harness implementing both QuotaHarness and AccountHarness
// with matching freshness windows runs only the quota ticker — no
// duplicate account ticker is registered.
func TestRefreshScheduler_AccountTickerSkippedWhenSameCadence(t *testing.T) {
	start := time.Date(2026, 5, 14, 12, 0, 0, 0, time.UTC)
	clock := newFakeClock(start)

	freshness := 30 * time.Minute
	combo := &comboHarness{
		quota: harnesstest.NewSyntheticQuotaHarness("combo", harnesses.QuotaStatus{
			State:      harnesses.QuotaOK,
			CapturedAt: start.Add(-2 * freshness),
		}, nil),
		account: harnesstest.NewSyntheticAccountHarness("combo", harnesses.AccountSnapshot{
			Authenticated: true,
			CapturedAt:    start.Add(-2 * freshness),
		}, freshness),
	}
	combo.quota.SetQuotaFreshness(freshness)

	notify := make(chan string, 8)
	sched := newRefreshScheduler(func(name string) harnesses.Harness {
		if name == "combo" {
			return combo
		}
		return nil
	}, []string{"combo"}, clock)
	sched.tickNotify = notify

	sched.Start(context.Background())
	t.Cleanup(sched.Stop)

	clock.Advance(freshness / 2)
	waitForTick(t, notify, time.Second)

	if got := combo.quota.ProbeCount(); got != 1 {
		t.Fatalf("quota probe count: %d want 1", got)
	}
	if got := combo.account.ProbeCount(); got != 0 {
		t.Fatalf("account probe count: %d want 0 (cadence matched, no separate ticker)", got)
	}
}

